// Catalog.jsx
import React, { useEffect, useState } from 'react';
import styled from 'styled-components';
import PlantCard from '../components/PlantCard';
import Sidebar from '../components/Sidebar';
//import { useCart } from '../Context/CartContext';  // <-- Import useCart

// Sample 8 plants data (same as before)
const samplePlants = [
  {
    _id: '1',
    name: 'Snake Plant',
    category: 'Indoor',
    image: 'https://cdn.pixabay.com/photo/2016/10/18/21/22/snake-plant-1756949_1280.jpg',
    shortDescription: 'Low maintenance indoor plant',
    longDescription: 'The Snake Plant is a hardy indoor plant that tolerates low light and irregular watering.',
    price: 15.99,
    quantity: 30,
  },
  {
    _id: '2',
    name: 'Rosemary',
    category: 'Medicinal',
    image: 'https://cdn.pixabay.com/photo/2018/02/20/18/16/rosemary-3163814_1280.jpg',
    shortDescription: 'Aromatic herb for cooking and medicine',
    longDescription: 'Rosemary is an evergreen herb used in cooking and natural remedies for various ailments.',
    price: 7.5,
    quantity: 50,
  },
  {
    _id: '3',
    name: 'Aloe Vera',
    category: 'Medicinal',
    image: 'https://cdn.pixabay.com/photo/2016/03/27/21/59/aloe-plant-1280369_1280.jpg',
    shortDescription: 'Healing succulent plant',
    longDescription: 'Aloe Vera is well-known for its healing properties for skin and burns.',
    price: 12.0,
    quantity: 40,
  },
  {
    _id: '4',
    name: 'Bonsai Tree',
    category: 'Bonsai',
    image: 'https://cdn.pixabay.com/photo/2017/04/17/21/40/bonsai-2239023_1280.jpg',
    shortDescription: 'Miniature artistic tree',
    longDescription: 'Bonsai trees are carefully cultivated miniatures of larger trees, popular as decorative plants.',
    price: 50.0,
    quantity: 15,
  },
  {
    _id: '5',
    name: 'Cactus',
    category: 'Succulents',
    image: 'https://cdn.pixabay.com/photo/2018/06/04/10/40/cactus-3456314_1280.jpg',
    shortDescription: 'Easy care succulent',
    longDescription: 'Cacti are drought-resistant plants, perfect for sunny windowsills and low maintenance.',
    price: 10.99,
    quantity: 60,
  },
  {
    _id: '6',
    name: 'Lavender',
    category: 'Outdoor',
    image: 'https://cdn.pixabay.com/photo/2016/07/10/16/37/lavender-1507659_1280.jpg',
    shortDescription: 'Fragrant flowering plant',
    longDescription: 'Lavender is a beautiful flowering plant, often used for its scent and calming properties.',
    price: 14.0,
    quantity: 25,
  },
  {
    _id: '7',
    name: 'Ficus',
    category: 'Indoor',
    image: 'https://cdn.pixabay.com/photo/2017/03/01/12/39/ficus-2104347_1280.jpg',
    shortDescription: 'Popular indoor ornamental tree',
    longDescription: 'Ficus plants are popular as houseplants, known for their glossy leaves and easy care.',
    price: 20.0,
    quantity: 35,
  },
  {
    _id: '8',
    name: 'Pruning Shears',
    category: 'Plant Tools',
    image: 'https://cdn.pixabay.com/photo/2016/05/24/16/26/pruning-plant-1410491_1280.jpg',
    shortDescription: 'Essential gardening tool',
    longDescription: 'High-quality pruning shears for trimming and shaping your plants with ease.',
    price: 18.99,
    quantity: 100,
  },
];

const Container = styled.div`
  display: flex;
  padding: 20px;
  font-family: 'Segoe UI', sans-serif;
`;

const PlantGrid = styled.div`
  flex: 1;
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
  gap: 20px;
`;

const DetailsSection = styled.div`
  width: 340px;
  margin-left: 20px;
  background: #f7fff7;
  padding: 20px;
  border-radius: 10px;
  border: 1px solid #cde3cd;
`;

const DetailsImage = styled.img`
  width: 100%;
  border-radius: 8px;
  margin-bottom: 15px;
`;

const DetailsTitle = styled.h2`
  color: #2e7d32;
  margin-bottom: 10px;
`;

const DetailsText = styled.p`
  font-size: 0.95rem;
  line-height: 1.4;
  margin-bottom: 8px;
`;

const Price = styled.p`
  font-weight: bold;
  font-size: 1.1rem;
  color: #1b5e20;
  margin-top: 15px;
`;

const Quantity = styled.p`
  font-size: 0.95rem;
  color: #555;
  margin-bottom: 20px;
`;

const ButtonGroup = styled.div`
  display: flex;
  flex-direction: column;
  gap: 12px;
`;

const Button = styled.button`
  padding: 10px;
  background-color: #2e7d32;
  color: white;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  font-weight: 600;
  font-size: 1rem;
  transition: background-color 0.3s ease;

  &:hover {
    background-color: #1b5e20;
  }

  &:disabled {
    background-color: #9ccc9c;
    cursor: not-allowed;
  }
`;

const QuantitySelector = styled.div`
  display: flex;
  align-items: center;
  margin-bottom: 15px;
  gap: 10px;

  button {
    background-color: #2e7d32;
    color: white;
    border: none;
    border-radius: 50%;
    width: 32px;
    height: 32px;
    font-size: 20px;
    cursor: pointer;
    font-weight: bold;
    transition: background-color 0.3s ease;

    &:hover {
      background-color: #1b5e20;
    }

    &:disabled {
      background-color: #9ccc9c;
      cursor: not-allowed;
    }
  }

  span {
    font-weight: 600;
    font-size: 1.1rem;
    width: 40px;
    text-align: center;
  }
`;

const Catalog = () => {
  const [plants, setPlants] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [selectedCategories, setSelectedCategories] = useState([]);
  const [selectedPlant, setSelectedPlant] = useState(null);
  const [quantity, setQuantity] = useState(1);

  // Use global cart context:
  //const { addToCart, removeFromCart, cartItems } = useCart();

  useEffect(() => {
    setPlants(samplePlants);
    setFiltered(samplePlants);
  }, []);

  useEffect(() => {
    if (selectedCategories.length === 0) {
      setFiltered(plants);
    } else {
      setFiltered(plants.filter((p) => selectedCategories.includes(p.category)));
    }
    setSelectedPlant(null);
  }, [selectedCategories, plants]);

  useEffect(() => {
    // Reset quantity when selectedPlant changes
    setQuantity(1);
  }, [selectedPlant]);

  const handleCategoryChange = (e) => {
    const { value, checked } = e.target;
    if (value === 'all') {
      if (checked) setSelectedCategories([]);
      else setSelectedCategories([]);
      setSelectedPlant(null);
      return;
    }
    setSelectedCategories((prev) =>
      checked ? [...prev, value] : prev.filter((cat) => cat !== value)
    );
    setSelectedPlant(null);
  };

  // New addToCart handler that adds quantity number of items
  const addToCartHandler = () => {
    if (!selectedPlant) return;
    for (let i = 0; i < quantity; i++) {
      addToCart(selectedPlant);
    }
    alert(`Added ${quantity} "${selectedPlant.name}" to cart!`);
  };

  const removeFromCartHandler = () => {
    if (!selectedPlant) return;
    removeFromCart(selectedPlant._id);
    alert(`Removed "${selectedPlant.name}" from cart!`);
  };

  const isInCart = selectedPlant
    ? cartItems.some((item) => item._id === selectedPlant._id)
    : false;

  const incrementQuantity = () => {
    if (quantity < (selectedPlant?.quantity || 1)) {
      setQuantity((q) => q + 1);
    }
  };

  const decrementQuantity = () => {
    if (quantity > 1) {
      setQuantity((q) => q - 1);
    }
  };

  const handleBookVisit = () => {
    if (!selectedPlant) return;
    alert(`Visit booked for "${selectedPlant.name}"!`);
  };

  const handleGetDelivery = () => {
    if (!selectedPlant) return;
    alert(`Delivery requested for "${selectedPlant.name}"!`);
  };

  return (
    <Container>
      <Sidebar selectedCategories={selectedCategories} onCategoryChange={handleCategoryChange} />
      <PlantGrid>
        {filtered.length > 0 ? (
          filtered.map((pl) => (
            <div
              key={pl._id}
              onClick={() => setSelectedPlant(pl)}
              style={{ cursor: 'pointer' }}
            >
              <PlantCard plant={pl} />
            </div>
          ))
        ) : (
          <p>No plants match the selected filters.</p>
        )}
      </PlantGrid>
      <DetailsSection>
        {selectedPlant ? (
          <>
            <DetailsImage src={selectedPlant.image} alt={selectedPlant.name} />
            <DetailsTitle>{selectedPlant.name}</DetailsTitle>
            <DetailsText>
              <strong>Short Description:</strong> {selectedPlant.shortDescription}
            </DetailsText>
            <DetailsText>
              <strong>Long Description:</strong> {selectedPlant.longDescription}
            </DetailsText>
            <Price>Price: ${selectedPlant.price.toFixed(2)}</Price>
            <Quantity>Available Quantity: {selectedPlant.quantity}</Quantity>

            <QuantitySelector>
              <button onClick={decrementQuantity} disabled={quantity <= 1}>
                -
              </button>
              <span>{quantity}</span>
              <button
                onClick={incrementQuantity}
                disabled={quantity >= selectedPlant.quantity}
              >
                +
              </button>
            </QuantitySelector>

            <ButtonGroup>
              {!isInCart ? (
                <Button onClick={addToCartHandler}>Add to Cart</Button>
              ) : (
                <Button onClick={removeFromCartHandler} style={{ backgroundColor: '#c62828' }}>
                  Remove from Cart
                </Button>
              )}
              <Button onClick={handleBookVisit}>Book Visit</Button>
              <Button onClick={handleGetDelivery}>Get Delivery</Button>
            </ButtonGroup>
          </>
        ) : (
          <p>Select a plant to see details</p>
        )}
      </DetailsSection>
    </Container>
  );
};

export default Catalog;
